import re

with open('curriculum/l2-uk-en/bio/hanna-barvinok.md', 'r', encoding='utf-8') as f:
    content = f.read()

# Append to Літературна діяльність
add_4_more = """
Дослідники її творчості також звертають увагу на те, як тонко вона використовувала народні повір'я та елементи магічного мислення у своїх текстах. Для Ганни Барвінок народна магія не була чимось екзотичним чи маргінальним; вона розуміла її як невіддільну частину селянського світогляду, як спосіб взаємодії з незбагненним світом природи та долі. У її оповіданнях заклинання, замовляння та звернення до знахарів часто стають останнім відчайдушним кроком людини, яка опинилася в безвихідній ситуації, коли офіційна релігія чи суспільні інститути вже не можуть допомогти. Такий підхід дозволив їй створити глибоко автентичний, багатовимірний образ українського села, де язичницькі вірування органічно переплітаються з християнською мораллю, створюючи неповторний культурний синтез. Її здатність фіксувати ці нюанси без жодного осуду чи зверхності робить її прозу справжнім скарбом для сучасних етнопсихологів та культурологів. Вона писала не для того, щоб розважити міського читача екзотикою, а для того, щоб задокументувати правду життя свого народу. Ця безпрецедентна чесність і глибока повага до своїх героїв стали її головним творчим кредо, якого вона неухильно дотримувалася протягом усього свого літературного шляху, залишивши нам у спадок твори, що не втрачають своєї актуальності і сьогодні.
"""

content = content.replace('## Пізній період', add_4_more + chr(10) + chr(10) + '## Пізній період')

with open('curriculum/l2-uk-en/bio/hanna-barvinok.md', 'w', encoding='utf-8') as f:
    f.write(content)
